# Bu script brand_logo.png ve sinyo_avatar.jpeg dosyalarini
# calistigi klasore yazar. Calistirmak icin: python install_images.py
import base64

LOGO_B64 = ""

SINYO_B64 = ""

with open("brand_logo.png", "wb") as f:
    f.write(base64.b64decode(LOGO_B64))
print("brand_logo.png yazildi")

with open("sinyo_avatar.jpeg", "wb") as f:
    f.write(base64.b64decode(SINYO_B64))
print("sinyo_avatar.jpeg yazildi")
